function solve(edges, online, k) {
    const n = online.length;
    const graph = new Map();

    // Build the graph
    for (const [u, v, cost] of edges) {
        if (!graph.has(u)) {
            graph.set(u, []);
        }
        graph.get(u).push([v, cost]);
    }

    // Use Dijkstra's algorithm to find the maximum minimum edge cost
    const maxMinCost = new Array(n).fill(-1);

    // Start from node 0
    const pq = new PriorityQueue();
    pq.enqueue([0, 0, Infinity]); // [node, currentMinCost, totalCost]

    while (!pq.isEmpty()) {
        const [node, currentMinCost, totalCost] = pq.dequeue();

        if (node === n - 1) {
            maxMinCost[n - 1] = Math.max(maxMinCost[n - 1], currentMinCost);
            continue;
        }

        if (totalCost > k) continue;

        if (!online[node]) continue;

        for (const [neighbor, edgeCost] of graph.get(node) || []) {
            if (!online[neighbor]) continue;

            const newTotalCost = totalCost + edgeCost;
            if (newTotalCost > k) continue;

            const newMinCost = Math.min(currentMinCost, edgeCost);

            if (maxMinCost[neighbor] < newMinCost) {
                pq.enqueue([neighbor, newMinCost, newTotalCost]);
            }
        }
    }

    return maxMinCost[n - 1] === -1 ? -1 : maxMinCost[n - 1];
}

